# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import Foundation

// MARK: - Models

struct PromoCode {
    let code: String
    let discountPercentage: Int
    let isValid: Bool
    let expirationDate: Date?
    let minimumPurchaseAmount: Double?
    let maxUsageCount: Int?
}

struct PromoApplicationResult {
    let success: Bool
    let message: String
    let appliedDiscount: Int?
    let promoCode: String?
}

enum PromoError: Error, LocalizedError {
    case invalidURL
    case missingPromoCode
    case missingDiscount
    case invalidDiscount
    case expiredPromo
    case alreadyRedeemed
    case userNotLoggedIn
    case networkError(String)
    case unknownError
    
    var errorDescription: String? {
        switch self {
        case .invalidURL: return "The promotional link is invalid."
        case .missingPromoCode: return "No promo code found in the link."
        case .missingDiscount: return "No discount information found in the link."
        case .invalidDiscount: return "The discount percentage is invalid."
        case .expiredPromo: return "This promotional offer has expired."
        case .alreadyRedeemed: return "This promo code has already been redeemed."
        case .userNotLoggedIn: return "Please log in to apply this promo code."
        case .networkError(let msg): return "Network error: \(msg)"
        case .unknownError: return "An unknown error occurred."
        }
    }
}

// MARK: - PromoService

class PromoService {
    
    static let shared = PromoService()
    
    private var redeemedCodes: Set<String> = []
    private var pendingPromo: (code: String, discount: Int)?
    
    private init() {
        loadRedeemedCodes()
    }
    
    // MARK: - URL Parsing
    
    func extractPromoParameters(from url: URL) -> Result<(code: String, discount: Int), PromoError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.invalidURL)
        }
        
        // Validate host and path
        guard components.host == "myapp.com", components.path == "/promo" else {
            return .failure(.invalidURL)
        }
        
        guard let queryItems = components.queryItems else {
            return .failure(.missingPromoCode)
        }
        
        guard let codeItem = queryItems.first(where: { $0.name == "code" }),
              let code = codeItem.value, !code.isEmpty else {
            return .failure(.missingPromoCode)
        }
        
        guard let discountItem = queryItems.first(where: { $0.name == "discount" }),
              let discountString = discountItem.value else {
            return .failure(.missingDiscount)
        }
        
        guard let discount = Int(discountString), discount > 0, discount <= 100 else {
            return .failure(.invalidDiscount)
        }
        
        return .success((code: code, discount: discount))
    }
    
    // MARK: - Promo Validation
    
    func validatePromoCode(_ code: String, discount: Int, completion: @escaping (Result<PromoCode, PromoError>) -> Void) {
        // Check if already redeemed locally
        if redeemedCodes.contains(code.uppercased()) {
            completion(.failure(.alreadyRedeemed))
            return
        }
        
        // Simulate server-side validation
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard self != nil else { return }
            
            // In production, this would be an API call to validate the promo code
            let promo = PromoCode(
                code: code.uppercased(),
                discountPercentage: discount,
                isValid: true,
                expirationDate: Calendar.current.date(byAdding: .day, value: 30, to: Date()),
                minimumPurchaseAmount: nil,
                maxUsageCount: 1
            )
            
            DispatchQueue.main.async {
                if let expiration = promo.expirationDate, expiration < Date() {
                    completion(.failure(.expiredPromo))
                } else {
                    completion(.success(promo))
                }
            }
        }
    }
    
    // MARK: - Apply Promo to User Account
    
    func applyPromoToAccount(code: String, discount: Int, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        
        guard UserAccountManager.shared.isLoggedIn else {
            // Store pending promo for after login
            pendingPromo = (code: code, discount: discount)
            completion(.failure(.userNotLoggedIn))
            return
        }
        
        validatePromoCode(code, discount: discount) { [weak self] result in
            switch result {
            case .success(let promo):
                // Simulate applying to the server
                DispatchQueue.global().asyncAfter(deadline: .now() + 0.3) {
                    DispatchQueue.main.async {
                        self?.redeemedCodes.insert(promo.code)
                        self?.saveRedeemedCodes()
                        
                        // Track analytics
                        AnalyticsTracker.shared.trackPromoRedemption(code: promo.code, discount: promo.discountPercentage)
                        
                        let result = PromoApplicationResult(
                            success: true,
                            message: "Promo code \(promo.code) applied! You get \(promo.discountPercentage)% off!",
                            appliedDiscount: promo.discountPercentage,
                            promoCode: promo.code
                        )
                        completion(.success(result))
                    }
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Pending Promo Management
    
    func applyPendingPromoIfNeeded(completion: @escaping (Result<PromoApplicationResult, PromoError>?) -> Void) {
        guard let pending = pendingPromo else {
            completion(nil)
            return
        }
        pendingPromo = nil
        applyPromoToAccount(code: pending.code, discount: pending.discount) { result in
            completion(result)
        }
    }
    
    func hasPendingPromo() -> Bool {
        return pendingPromo != nil
    }
    
    // MARK: - Persistence
    
    private func loadRedeemedCodes() {
        if let codes = UserDefaults.standard.array(forKey: "redeemedPromoCodes") as? [String] {
            redeemedCodes = Set(codes)
        }
    }
    
    private func saveRedeemedCodes() {
        UserDefaults.standard.set(Array(redeemedCodes), forKey: "redeemedPromoCodes")
    }
}

// MARK: - UserAccountManager

class UserAccountManager {
    static let shared = UserAccountManager()
    
    private(set) var isLoggedIn: Bool = false
    private(set) var currentUserId: String?
    private(set) var appliedDiscounts: [String: Int] = [:]
    
    private init() {}
    
    func login(userId: String, completion: @escaping (Bool) -> Void) {
        // Simulate login
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
            self?.isLoggedIn = true
            self?.currentUserId = userId
            completion(true)
            
            // Check for pending promos after login
            PromoService.shared.applyPendingPromoIfNeeded { result in
                if case .success(let promoResult) = result {
                    NotificationCenter.default.post(
                        name: .promoAppliedAfterLogin,
                        object: nil,
                        userInfo: ["result": promoResult]
                    )
                }
            }
        }
    }
    
    func logout() {
        isLoggedIn = false
        currentUserId = nil
        appliedDiscounts.removeAll()
    }
    
    func applyDiscount(code: String, percentage: Int) {
        appliedDiscounts[code] = percentage
    }
}

