// MARK: - DeepLinkRouter

class DeepLinkRouter {
    
    static let shared = DeepLinkRouter()
    
    private init() {}
    
    enum DeepLinkType {
        case promo(code: String, discount: Int)
        case unknown
    }
    
    func route(url: URL) -> DeepLinkType {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .unknown
        }
        
        guard components.host == "myapp.com" else {
            return .unknown
        }
        
        switch components.path {
        case "/promo":
            let result = PromoService.shared.extractPromoParameters(from: url)
            switch result {
            case .success(let params):
                return .promo(code: params.code, discount: params.discount)
            case .failure:
                return .unknown
            }
        default:
            return .unknown
        }
    }
    
    func handleDeepLink(_ url: URL, from viewController: UIViewController) {
        let linkType = route(url: url)
        
        switch linkType {
        case .promo(let code, let discount):
            AnalyticsTracker.shared.trackPromoLinkOpened(code: code, discount: discount, source: determineSource(from: url))
            let promoVC = PromoViewController(promoCode: code, discountPercentage: discount)
            viewController.present(promoVC, animated: true)
            
        case .unknown:
            print("Unknown deep link: \(url)")
        }
    }
    
    private func determineSource(from url: URL) -> String {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return "unknown"
        }
        
        if let source = queryItems.first(where: { $0.name == "utm_source" })?.value {
            return source
        }
        
        if let medium = queryItems.first(where: { $0.name == "utm_medium" })?.value {
            return medium
        }
        
        return "direct"
    }
}

// MARK: - SceneDelegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let mainVC = MainViewController()
        let navController = UINavigationController(rootViewController: mainVC)
        window.rootViewController = navController
        self.window = window
        window.makeKeyAndVisible()
        
        // Handle universal link if app was launched via one
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleIncomingURL(url)
        }
        
        // Handle URL contexts (for custom URL schemes)
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
    }
    
    // Handle universal links when app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    // Handle URL scheme links
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        guard let rootVC = window?.rootViewController else { return }
        
        // Find the topmost presented view controller
        var topVC = rootVC
        while let presented = topVC.presentedViewController {
            topVC = presented
        }
        
        DeepLinkRouter.shared.handleDeepLink(url, from: topVC)
    }
}

// MARK: - AppDelegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        let config = UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
        config.delegateClass = SceneDelegate.self
        return config
    }
    
    // Fallback for iOS 12 and earlier - Universal Links
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        let linkType = DeepLinkRouter.shared.route(url: url)
        switch linkType {
        case .promo:
            return true
        case .unknown:
            return false
        }
    }
}

