        loginButton.addTarget(self, action: #selector(simulateLogin), for: .touchUpInside)
    }
    
    private func setupObservers() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handlePromoAppliedAfterLogin(_:)),
            name: .promoAppliedAfterLogin,
            object: nil
        )
    }
    
    @objc private func testPromoLink() {
        // Simulate receiving a universal link
        guard let testURL = URL(string: "https://myapp.com/promo?code=SUMMER2024&discount=25") else { return }
        DeepLinkRouter.shared.handleDeepLink(testURL, from: self)
    }
    
    @objc private func simulateLogin() {
        UserAccountManager.shared.login(userId: "user_\(Int.random(in: 1000...9999))") { [weak self] success in
            if success {
                self?.statusLabel.text = "Logged in as \(UserAccountManager.shared.currentUserId ?? "unknown")"
            }
        }
    }
    
    @objc private func handlePromoAppliedAfterLogin(_ notification: Notification) {
        if let result = notification.userInfo?["result"] as? PromoApplicationResult {
            statusLabel.text = result.message
            if let code = result.promoCode, let discount = result.appliedDiscount {
                appliedPromos.append((code: code, discount: discount))
                appliedPromosTableView.reloadData()
            }
        }
    }
}

// MARK: - UITableViewDataSource & Delegate

extension MainViewController: UITableViewDataSource, UITableViewDelegate {
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return appliedPromos.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "PromoCell", for: indexPath)
        let promo = appliedPromos[indexPath.row]
        
        var config = cell.defaultContentConfiguration()
        config.text = "Code: \(promo.code)"
        config.secondaryText = "Discount: \(promo.discount)%"
        config.image = UIImage(systemName: "tag.fill")
        config.imageProperties.tintColor = .systemGreen
        cell.contentConfiguration = config
        
        return cell
    }
    
    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        return appliedPromos.isEmpty ? nil : "Applied Promo Codes"
    }
}